#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void king() {
    int n;
    scanf("%d", &n);
    char s[n+1];
    scanf("%s", s);
    int a[n];
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (s[i] == '*') {
            a[count++] = i + 1;
        }
    }

    if (count < 5) {
        printf("no\n");
        return;
    }

    for (int i1 = 0; i1 < count; i1++) {
        for (int i2 = i1 + 1; i2 < count; i2++) {
            for (int i3 = i2 + 1; i3 < count; i3++) {
                for (int i4 = i3 + 1; i4 < count; i4++) {
                    for (int i5 = i4 + 1; i5 < count; i5++) {
                        int arr[5] = {a[i1], a[i2], a[i3], a[i4], a[i5]};
                        int mine[4];
                        for (int i = 0; i < 4; i++) {
                            mine[i] = arr[i+1] - arr[i];
                        }
                        int all_same = 1;
                        for (int i = 1; i < 4; i++) {
                            if (mine[i] != mine[0]) {
                                all_same = 0;
                                break;
                            }
                        }
                        if (all_same) {
                            printf("yes\n");
                            return;
                        }
                    }
                }
            }
        }
    }

    printf("no\n");
}

int main() {
    king();
    return 0;
}
